Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table names to their corresponding C++ types
  std::map<std::string, rfl::Type> table_type_map = {
    {"Student", rfl::type<Student>()},
    {"Course", rfl::type<Course>()},
    {"Score", rfl::type<Score>()},
    {"Major", rfl::type<Major>()}
  };

  // Get the appropriate type based on table name
  auto type_result = table_type_map.find(table_name);
  if (type_result == table_type_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  // Connect to database and perform insertion
  auto result = sqlgen::sqlite::connect(db_path)
      .and_then(sqlgen::insert(records))
      .value();
}

void modify_eas_records_by_id(const std::string& table_name,
                               const int record_id,
                               const std::string& col_name,
                               const auto& new_value) {
  // Map table names to their corresponding C++ types
  std::map<std::string, rfl::Type> table_type_map = {
    {"Student", rfl::type<Student>()},
    {"Course", rfl::type<Course>()},
    {"Score", rfl::type<Score>()},
    {"Major", rfl::type<Major>()}
  };

  // Get the appropriate type based on table name
  auto type_result = table_type_map.find(table_name);
  if (type_result == table_type_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  // Determine primary key column based on table type
  std::string primary_key_col;
  if (table_name == "Student") {
    primary_key_col = "SNo";
  } else if (table_name == "Course") {
    primary_key_col = "CID";
  } else if (table_name == "Score") {
    primary_key_col = "ScID";
  } else if (table_name == "Major") {
    primary_key_col = "MID";
  } else {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  // Build and execute update statement
  auto result = sqlgen::sqlite::connect(db_path)
      .and_then(sqlgen::update<type_result->second>(
          set(col_name + "_c" = new_value)
      ) | where(primary_key_col + "_c" == record_id))
      .value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const int record_id) {
  // Map table names to their corresponding C++ types
  std::map<std::string, rfl::Type> table_type_map = {
    {"Student", rfl::type<Student>()},
    {"Course", rfl::type<Course>()},
    {"Score", rfl::type<Score>()},
    {"Major", rfl::type<Major>()}
  };

  // Get the appropriate type based on table name
  auto type_result = table_type_map.find(table_name);
  if (type_result == table_type_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  // Determine primary key column based on table type
  std::string primary_key_col;
  if (table_name == "Student") {
    primary_key_col = "SNo";
  } else if (table_name == "Course") {
    primary_key_col = "CID";
  } else if (table_name == "Score") {
    primary_key_col = "ScID";
  } else if (table_name == "Major") {
    primary_key_col = "MID";
  } else {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  // Build and execute delete statement
  auto result = sqlgen::sqlite::connect(db_path)
      .and_then(sqlgen::delete_from<type_result->second> | 
                where(primary_key_col + "_c" == record_id))
      .value();
}
```

## Key Implementation Details:

1. **Table Type Mapping**: Uses a `std::map` to associate table names with their corresponding C++ struct types for type-safe operations.

2. **Primary Key Handling**: Each table has a different primary key column name, which is determined based on the table type.

3. **SQLGen Integration**:
   - Uses `sqlgen::sqlite::connect()` to establish database connections
   - Uses `sqlgen::insert()` for batch record insertion
   - Uses `sqlgen::update()` with `set()` and `where()` for conditional updates
   - Uses `sqlgen::delete_from()` with `where()` for conditional deletions

4. **Error Handling**: Includes basic validation for invalid table names.

5. **Type Safety**: Leverages C++ template system and rfl::Type for compile-time type checking.

The implementation follows sqlgen's fluent API pattern and properly handles the different data types and primary key structures defined in the EAS database schema.

