namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false; // Connection failed
    }
    auto conn = *conn_result;

    // Start a transaction for atomic batch update
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false; // Transaction start failed
    }

    try {
        // Create the update statement with SET clauses
        auto update_stmt = sqlgen::update<Document>(
            sqlgen::col<"is_deleted">.set(1),
            sqlgen::col<"deleted_at">.set(sqlgen::current_timestamp)
        );

        // Apply WHERE condition using IN clause for batch update
        auto where_condition = sqlgen::col<"doc_id">.in(ids);
        auto full_update = update_stmt | sqlgen::where(where_condition);

        // Execute the batch update
        auto update_result = full_update(conn);
        if (!update_result) {
            conn->rollback();
            return false; // Update failed
        }

        // Commit the transaction if successful
        auto commit_result = conn->commit();
        if (!commit_result) {
            conn->rollback();
            return false; // Commit failed
        }

        return true; // Success

    } catch (...) {
        // Rollback on any exception
        conn->rollback();
        return false;
    }
}

}  // namespace soft_delete_records
```

