#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return false;
  }

  try {
    // Verify sufficient funds
    auto from_account = sqlgen::read<std::vector<Account>> 
                       | sqlgen::where("account_id"_c == from_account_id);
    auto from_result = from_account(conn);

    if (!from_result || from_result.value().empty()) {
      conn->rollback();
      return false;
    }

    auto from_balance = from_result.value()[0].balance;
    if (from_balance < amount) {
      conn->rollback();
      return false;
    }

    // Update from_account: balance = balance - amount
    auto update_from = sqlgen::update<Account>(
        sqlgen::set("balance"_c, "balance"_c - amount)
    ) | sqlgen::where("account_id"_c == from_account_id);

    auto update_from_result = update_from(conn);
    if (!update_from_result) {
      conn->rollback();
      return false;
    }

    // Update to_account: balance = balance + amount
    auto update_to = sqlgen::update<Account>(
        sqlgen::set("balance"_c, "balance"_c + amount)
    ) | sqlgen::where("account_id"_c == to_account_id);

    auto update_to_result = update_to(conn);
    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
      conn->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
