  auto conn = conn_result.value();

  // Create tables
  auto create_user = sqlgen::create_table<User>{};
  auto create_friendship = sqlgen::create_table<Friendship>{};

  create_user(conn).value();
  create_friendship(conn).value();

  // Insert data
  auto insert_users = sqlgen::insert(users);
  auto insert_friendships = sqlgen::insert(friendships);

  insert_users(conn).value();
  insert_friendships(conn).value();

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_query = sqlgen::select_from<User, "t1">(
      "username"_t1 | sqlgen::as<"user1_name">,
      "username"_t2 | sqlgen::as<"user2_name">,
      sqlgen::count() | sqlgen::as<"mutual_count">
  )
  | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_f1)
  | sqlgen::inner_join<Friendship, "f2">("user_id2"_f1 == "user_id1"_f2)
  | sqlgen::inner_join<User, "t2">("user_id2"_f2 == "user_id"_t2)
  | sqlgen::where("user_id"_t1 < "user_id"_t2)
  | sqlgen::group_by("user_id"_t1, "user_id"_t2)
  | sqlgen::having(sqlgen::count() > 0);

  auto mutual_results = sqlgen::read<std::vector<FriendConnection>>(mutual_query)(conn);
  if (!mutual_results) {
