  | sqlgen::where(sqlgen::count("user_id2"_f1) > 
      (sqlgen::select_from<Friendship>(sqlgen::count()) 
       | sqlgen::group_by("user_id1")
       | sqlgen::to<double>))
  | sqlgen::group_by("user_id"_t1, "username"_t1);

  // Query 3: Friend-of-friend relationships
