      "username"_t1,
      sqlgen::count("user_id2"_f1) | sqlgen::as<"friend_count">
  )
  | sqlgen::left_join<Friendship, "f1">("user_id"_t1 == "user_id1"_f1)
  | sqlgen::group_by("user_id"_t1, "username"_t1)
  | sqlgen::order_by(sqlgen::count("user_id2"_f1).desc());

  // Query 5: Same city recommendations
  auto recommendation_query = sqlgen::select_from<User, "t1">(
      "username"_t1 | sqlgen::as<"user1_name">,
      "username"_t2 | sqlgen::as<"user2_name">,
