  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Create update query using sqlgen::update with set operation
  // 3. Use string replacement operation on the content column
  auto update_query = sqlgen::update<Note>(
    "content"_c.set("content"_c.replace("foo", "bar"))
  );

  // 4. Execute the update query on the connection
